import {
  ExternalLink,
  Globe,
  MessageCircle,
  Send,
  type LucideIcon,
} from "lucide-react";
import { type DexLeaderboardRow } from "@/services/orderly";
import { formatNumberRoundedDown } from "@/utils/format";
import { LocalizedLink } from "@/utils/localizedRoute";

export function formatCurrency(value: unknown): string {
  const n = Number(value ?? 0);
  if (!Number.isFinite(n)) return "—";
  const sign = n < 0 ? "-" : "";
  const abs = Math.abs(n);
  if (abs > 0 && abs < 0.01) return "<$0.01";
  const fmt = (next: number) => formatNumberRoundedDown(next, 2);
  if (abs >= 1e9) return `${sign}$${fmt(abs / 1e9)}B`;
  if (abs >= 1e6) return `${sign}$${fmt(abs / 1e6)}M`;
  if (abs >= 1e3) return `${sign}$${fmt(abs / 1e3)}K`;
  return `${sign}$${fmt(abs)}`;
}

export function getDexName(
  row: DexLeaderboardRow,
  fallback = "Unnamed DEX"
): string {
  return (
    row.brokerName ||
    row.broker_name ||
    row.name ||
    row.brokerId ||
    row.broker_id ||
    fallback
  );
}

export function getBrokerId(row: DexLeaderboardRow): string {
  return row.brokerId || row.broker_id || "—";
}

export function getLogo(row: DexLeaderboardRow): string | null {
  return row.logo || row.primaryLogo || null;
}

export function getVolume(row: DexLeaderboardRow): number {
  return (
    Number(
      row.totalVolume ?? row.volume_30d ?? row.volume30d ?? row.volume ?? 0
    ) || 0
  );
}

export function getFee(row: DexLeaderboardRow): number {
  return Number(row.totalBrokerFee ?? row.totalFee ?? row.fees ?? 0) || 0;
}

export function DexLogo({
  dex,
  size = "md",
}: {
  dex: DexLeaderboardRow;
  size?: "sm" | "md" | "lg";
}) {
  const name = getDexName(dex);
  const logo = getLogo(dex);
  const classes =
    size === "lg"
      ? "h-14 w-14 shrink-0 text-lg"
      : size === "sm"
        ? "h-8 w-8 shrink-0 text-xs"
        : "h-10 w-10 shrink-0 text-sm";
  if (logo)
    return (
      <img
        src={logo}
        alt=""
        className={`${classes} rounded-xl object-contain`}
      />
    );
  return (
    <div
      className={`${classes} flex items-center justify-center rounded-xl bg-(--bg-brand) font-bold text-(--fg-primary)`}
    >
      {name.slice(0, 2).toUpperCase()}
    </div>
  );
}

export function DexToken({ dex }: { dex: DexLeaderboardRow }) {
  const hasToken =
    dex.tokenSymbol || dex.tokenName || dex.tokenImageUrl || dex.tokenAddress;
  if (!hasToken) return null;

  return (
    <div className="flex items-center gap-2">
      {dex.tokenImageUrl ? (
        <img
          src={dex.tokenImageUrl}
          alt=""
          className="h-7 w-7 rounded-full object-cover"
        />
      ) : (
        <div className="flex h-7 w-7 items-center justify-center rounded-full bg-(--bg-brand) text-[10px] font-bold text-(--fg-primary)">
          {(dex.tokenSymbol || "TK").slice(0, 2).toUpperCase()}
        </div>
      )}
      <div className="min-w-0">
        <div className="truncate text-xs font-semibold text-(--fg-primary)">
          {dex.tokenSymbol || "—"}
        </div>
        <div className="max-w-[140px] truncate text-xs text-(--fg-secondary)">
          {dex.tokenName || dex.tokenChain || dex.tokenAddress || "—"}
        </div>
      </div>
    </div>
  );
}

function XLogo({ className = "h-3.5 w-3.5" }: { className?: string }) {
  return (
    <svg
      viewBox="0 0 24 24"
      aria-hidden="true"
      className={className}
      fill="currentColor"
    >
      <path d="M18.9 2h3.3l-7.2 8.2L23.5 22h-6.7l-5.2-6.8L5.6 22H2.3l7.7-8.8L1.8 2h6.8l4.7 6.2L18.9 2Zm-1.2 17.9h1.8L7.6 4H5.7l12 15.9Z" />
    </svg>
  );
}

export function DexSocials({
  dex,
  labels,
}: {
  dex: DexLeaderboardRow;
  labels: {
    website: string;
    telegram: string;
    discord: string;
    x: string;
    dex: string;
  };
}) {
  const links: Array<{
    label: string;
    href?: string | null;
    icon: LucideIcon | typeof XLogo;
  }> = [
    { label: labels.website, href: dex.websiteUrl, icon: Globe },
    { label: labels.telegram, href: dex.telegramLink, icon: Send },
    { label: labels.discord, href: dex.discordLink, icon: MessageCircle },
    { label: labels.x, href: dex.xLink, icon: XLogo },
    { label: labels.dex, href: dex.dexUrl, icon: ExternalLink },
  ];
  const activeLinks = links.filter(link => Boolean(link.href)) as Array<{
    label: string;
    href: string;
    icon: LucideIcon | typeof XLogo;
  }>;

  if (activeLinks.length === 0) return null;

  return (
    <div className="flex justify-end gap-1.5">
      {activeLinks.map(({ label, href, icon: Icon }) => (
        <a
          key={label}
          href={href}
          target="_blank"
          rel="noopener noreferrer"
          title={label}
          onClick={event => event.stopPropagation()}
          className="inline-flex h-7 w-7 items-center justify-center rounded-full border border-(--line-subtle) text-(--fg-secondary) hover:bg-(--bg-hover) hover:text-(--fg-primary)"
        >
          <Icon className="h-3.5 w-3.5" />
        </a>
      ))}
    </div>
  );
}

