export interface LeaderboardCardLabels {
  unnamedDex: string;
  noDescription: string;
  volumeForPeriod: string;
  builderRevenue: string;
  website: string;
  telegram: string;
  discord: string;
  x: string;
  dex: string;
}

export function LeaderboardCard({
  dex,
  rank,
  href,
  labels,
}: {
  dex: DexLeaderboardRow;
  rank?: number;
  href?: string;
  labels: LeaderboardCardLabels;
}) {
  const name = getDexName(dex, labels.unnamedDex);
  const cardContent = (
    <>
      <div className="relative">
        <div className="mb-6 flex items-start justify-between gap-4">
          <DexLogo dex={dex} size="lg" />
          {rank != null && (
            <div className="rounded-full bg-(--bg-warning-subtle) px-3 py-1 text-sm text-(--fg-warning)">
              #{rank}
            </div>
          )}
        </div>
        <h2 className="text-xl font-semibold text-(--fg-primary)">{name}</h2>
        <p className="mt-3 line-clamp-2 min-h-[40px] text-sm leading-5 text-(--fg-secondary)">
          {dex.description || labels.noDescription}
        </p>
        <div className="mt-5 grid grid-cols-2 gap-3">
          <div>
            <div className="text-[10px] uppercase tracking-[1.5px] text-(--fg-secondary)">
              {labels.volumeForPeriod}
            </div>
            <div className="mt-1 text-lg font-bold text-(--fg-primary)">
              {formatCurrency(getVolume(dex))}
            </div>
          </div>
          <div>
            <div className="text-[10px] uppercase tracking-[1.5px] text-(--fg-secondary)">
              {labels.builderRevenue}
            </div>
            <div className="mt-1 text-lg font-bold text-gradient-positive">
              {formatCurrency(getFee(dex))}
            </div>
          </div>
        </div>
        <div className="mt-5 flex items-center gap-3 border-t border-(--line-subtle) pt-4">
          <div className="flex-1">
            <DexToken dex={dex} />
          </div>
          <DexSocials dex={dex} labels={labels} />
        </div>
      </div>
    </>
  );

  if (href) {
    return (
      <LocalizedLink
        to={href}
        className="group relative overflow-hidden rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary) p-5 text-left transition-colors hover:border-(--line-brand)"
      >
        {cardContent}
      </LocalizedLink>
    );
  }

  return (
    <div className="group relative overflow-hidden rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary) p-5 text-left">
      {cardContent}
    </div>
  );
}
